INSERT INTO spectrum_australian_footnotes(footnote_ref, footnote_text, page) VALUES('AUS1A', 'In the band 1 260–1 300 MHz it is intended to accommodate radionavigation–satellite systems on a shared basis with defence applications.', 113);
INSERT INTO spectrum_australian_footnotes(footnote_ref, footnote_text, page) VALUES('AUS3', 'The use of the band 1 435–1 535 MHz by the aeronautical mobile service for telemetry has priority over other uses by the mobile service.', 113);
INSERT INTO spectrum_australian_footnotes(footnote_ref, footnote_text, page) VALUES('AUS7', 'Operation of stations of the aeronautical mobile (OR) service on a primary basis in Australia is on the condition that harmful interference is not caused to stations of services of other countries operating in accordance with the Radio Regulations.', 113);
INSERT INTO spectrum_australian_footnotes(footnote_ref, footnote_text, page) VALUES('AUS9', 'The bands 4 152–4 172 kHz, 6 233–6 261 kHz, 8 300–8 340 kHz, 12 368–12 420 kHz, 16 549–16 617 kHz, 18 846–18 870 kHz, 22 180– 22 240 kHz and 25 121–25 161.25 kHz are designated to be used principally for the purposes of defence. The Department of Defence is normally consulted in considering non-defence use of these bands.', 113);
INSERT INTO spectrum_australian_footnotes(footnote_ref, footnote_text, page) VALUES('AUS10', 'Operation of stations of the aeronautical mobile (OR) service on a secondary basis in Australia is on the condition that harmful interference is not caused to stations of services of other countries operating in accordance with the Radio Regulations.', 113);
INSERT INTO spectrum_australian_footnotes(footnote_ref, footnote_text, page) VALUES('AUS12', 'Operation of the amateur service in the band 7 100–7 300 kHz is subject to the conditions of Radio Regulation No. 4.4.', 113);
INSERT INTO spectrum_australian_footnotes(footnote_ref, footnote_text, page) VALUES('AUS24', 'The introduction of new stations of the broadcasting service in the band 85–87.5 MHz is subject to special agreements between Australia and other administrations. Television services operating in this band may be transferred to other broadcasting bands.', 113);
INSERT INTO spectrum_australian_footnotes(footnote_ref, footnote_text, page) VALUES('AUS25', 'Operation of the aeronautical mobile (R) service in the bands 108– 117.975 MHz and 117.975–137 MHz, and of the aeronautical radionavigation service in the bands 74.8–75.2 MHz, 108– 117.975 MHz, 328.6–335.4 MHz, 960–1 215 MHz and 5 000– 5 250 MHz is subject to the provisions of Annex 10 to the Convention on International Civil Aviation and the Standards and Recommended Practices of the International Civil Aviation Organisation (ICAO).', 113);
INSERT INTO spectrum_australian_footnotes(footnote_ref, footnote_text, page) VALUES('AUS26', 'The allocation to the broadcasting service in the band 137–144 MHz will remain until existing stations of that service are transferred to other broadcasting bands. No new assignments will be made to broadcasting services in this band.', 113);
INSERT INTO spectrum_australian_footnotes(footnote_ref, footnote_text, page) VALUES('AUS29', 'In these bands the radiolocation service is primary in offshore areas. Part 3', 113);
INSERT INTO spectrum_australian_footnotes(footnote_ref, footnote_text, page) VALUES('AUS32', 'The band 918–926 MHz (centre frequency 922 MHz) is designated for industrial, scientific and medical (ISM) applications. Radiocommunication stations operating within this band must accept harmful interference which may be caused by these applications. ISM equipment operating in this band is subject to the provisions of Radio Regulation No. 15.13.', 114);
INSERT INTO spectrum_australian_footnotes(footnote_ref, footnote_text, page) VALUES('AUS49', 'The use and assignment of frequencies to non-directional beacons (NDBs) of the aeronautical radionavigation service in the bands 190– 405 kHz, 415–495 kHz, 505–526.5 kHz and 1 606.5–1 800 kHz shall take account of Annex 10 to the Convention on International Civil Aviation and the Standards and Recommended Practices of the International Civil Aviation Organisation (ICAO).', 114);
INSERT INTO spectrum_australian_footnotes(footnote_ref, footnote_text, page) VALUES('AUS50', 'The use of the bands 526.5–535 kHz and 535–1 606.5 kHz by the broadcasting service shall take into account the provisions of the Final Acts of the Regional Administrative LF/MF Broadcasting Conference (Regions 1 and 3), Geneva, 1975.', 114);
INSERT INTO spectrum_australian_footnotes(footnote_ref, footnote_text, page) VALUES('AUS51', 'Use of the bands 2 850–3 025 kHz, 3 400–3 500 kHz, 4 650–4 700 kHz, 5 480–5 680 kHz, 6 525–6 685 kHz, 8815–8 965 kHz, 10 005– 10 100 kHz, 11 275–11 400 kHz, 13 260–13 360 kHz, 17 900– 17 970 kHz and 21 924–22 000 kHz by the aeronautical mobile (R) service is subject to the provisions of Appendix 27 of the Radio Regulations.', 114);
INSERT INTO spectrum_australian_footnotes(footnote_ref, footnote_text, page) VALUES('AUS52', 'Chapter VIII and other provisions of the Radio Regulations are applicable to the use of the bands 3 025–3 155 kHz, 3 900–3 950 kHz, 4 700–4 750 kHz, 5 450–5 480 kHz, 5 680–5 730 kHz, 6 685– 6 765 kHz, 8 965–9 040 kHz, 11 175–11 275 kHz, 13 200–13 260 kHz, 15 060–15 100 kHz, 17 970–18 030 kHz and 23 200–23 350 kHz by the aeronautical mobile (OR) service.', 114);
INSERT INTO spectrum_australian_footnotes(footnote_ref, footnote_text, page) VALUES('AUS53', 'The provisions of Appendix 17 and Chapter IX of the Radio Regulations apply to the use of the bands 4 063–4 438 kHz, 6 200–6 525 kHz, 8 195–8 815 kHz, 12 230–13 200 kHz, 16 360–17 410 kHz, 18 780– 19 800 kHz, 22 000–22 855 kHz and 25 070–26 175 kHz only where allocated to the maritime mobile service.', 114);
INSERT INTO spectrum_australian_footnotes(footnote_ref, footnote_text, page) VALUES('AUS54', 'The use of the bands 5 950–6 200 kHz, 7 200–7 300 kHz, 9 500– 9 900 kHz, 11 650–12 050 kHz, 13 600–13 800 kHz, 15 100– 15 600 kHz, 17 550–17 900 kHz, 21 450–21 850 kHz and 25 670– 26 100 kHz by the broadcasting service shall be in accordance with the provisions of Articles 11 and 12 of the Radio Regulations.', 114);
INSERT INTO spectrum_australian_footnotes(footnote_ref, footnote_text, page) VALUES('AUS57', 'This band may be used by stations of the radiolocation service for the purposes of defence, on condition that harmful interference is not caused to other services operating in accordance with this Spectrum Plan or the Radio Regulations.', 115);
INSERT INTO spectrum_australian_footnotes(footnote_ref, footnote_text, page) VALUES('AUS58', 'This band may be used by stations of the fixed and mobile services for the purposes of defence on condition that harmful interference is not caused to stations of other services operating in accordance with this Spectrum Plan or the Radio Regulations.', 115);
INSERT INTO spectrum_australian_footnotes(footnote_ref, footnote_text, page) VALUES('AUS59', 'Stations of the fixed and mobile services used for the purposes of defence may use the frequency bands specified in AUS9 on condition that harmful interference is not caused to stations of other services operating in accordance with this Spectrum Plan or the Radio Regulations.', 115);
INSERT INTO spectrum_australian_footnotes(footnote_ref, footnote_text, page) VALUES('AUS62', 'Parts of this band might be used in the future for the purposes of defence.', 115);
INSERT INTO spectrum_australian_footnotes(footnote_ref, footnote_text, page) VALUES('AUS64', 'The band 960–1 215 MHz may be used by stations of the fixed and mobile services using spread spectrum modulation for the purposes of defence on condition that harmful interference is not caused to stations of other services operating in accordance with this Spectrum Plan or the Radio Regulations.', 115);
INSERT INTO spectrum_australian_footnotes(footnote_ref, footnote_text, page) VALUES('AUS65', 'Geographical and operational constraints will apply to the mobile– satellite service when observations are being made by the Australia Telescope in the 1 660 MHz–1 660.5 MHz band.', 115);
INSERT INTO spectrum_australian_footnotes(footnote_ref, footnote_text, page) VALUES('AUS66', 'The band 151.4125–153 MHz is also allocated to the radiodetermination service on a secondary basis.', 115);
INSERT INTO spectrum_australian_footnotes(footnote_ref, footnote_text, page) VALUES('AUS67', 'Tropospheric scatter systems used for the purposes of defence may operate in the bands between 4 400 and 5 000 MHz. The possible requirement to coordinate with the fixed–satellite service should be noted (see International Footnote No. 441 at Part 4 of this Spectrum Plan).', 115);
INSERT INTO spectrum_australian_footnotes(footnote_ref, footnote_text, page) VALUES('AUS68', 'Underground mine communications systems are authorised to operate in the bands designated by this footnote on the condition that harmful interference is not caused to stations of other services operating in accordance with this Spectrum Plan or the Radio Regulations.', 115);
INSERT INTO spectrum_australian_footnotes(footnote_ref, footnote_text, page) VALUES('AUS73', 'The provisions of No. 52.220 and Appendix 17 of the Radio Regulations are applicable to the use of the band 8 100–8 195 kHz by the maritime mobile service. Part 3', 115);
INSERT INTO spectrum_australian_footnotes(footnote_ref, footnote_text, page) VALUES('AUS74', 'The use of the bands 526.5–535 kHz and 535–1 606.5 kHz by the fixed service shall be subject to the condition that no harmful interference shall be caused to the reception of transmissions by stations of the broadcasting service operating in accordance with this Spectrum Plan or the Radio Regulations.', 116);
INSERT INTO spectrum_australian_footnotes(footnote_ref, footnote_text, page) VALUES('AUS75', 'Use of this service by stations shall be subject to the condition that no harmful interference is caused to stations of other services operating in accordance with this Spectrum Plan or the Radio Regulations.', 116);
INSERT INTO spectrum_australian_footnotes(footnote_ref, footnote_text, page) VALUES('AUS87', 'Radio astronomy facilities operated by the CSIRO at the Paul Wild Observatory Narrabri (latitude 30° 18'' 46.40" S, longitude 149° 33'' 0.44" E), the Parkes Observatory (latitude 32° 59'' 54.25" S, longitude 148° 15'' 48.65" E) and the Mopra Observatory Coonabarabran (latitude 31° 16'' 04.12" S, longitude 149° 05'' 58.72" E) and by the University of Tasmania at the Mount Pleasant Observatory Hobart (latitude 42° 48'' 12.92" S, longitude 147° 26'' 25.86" E) and the Ceduna Observatory (latitude 31° 52'' 03.69" S, longitude 133° 48'' 35.40" E), and at the Canberra Deep Space Communication Complex (latitude 35° 23'' 54.46" S, longitude 148° 58'' 39.66" E) conduct passive observations in the frequency bands 1.2–1.8 GHz, 2.2–2.7 GHz, 4.5–6.7 GHz, 8–10 GHz and 16–26 GHz using receivers that are highly sensitive to interference. The Paul Wild and Mopra observatories also operate in the bands 30– 50 GHz and 75–115 GHz.', 116);
INSERT INTO spectrum_australian_footnotes(footnote_ref, footnote_text, page) VALUES('AUS88', 'In the band 12.2–12.5 GHz, transponders on space stations of the fixed– satellite service may be used additionally for transmissions in the broadcasting-satellite service. Such emissions shall comply with the power flux density limits prescribed for the fixed–satellite service in this band.', 116);
INSERT INTO spectrum_australian_footnotes(footnote_ref, footnote_text, page) VALUES('AUS89', 'Use of the band 54–56 MHz by the radiolocation service is limited to wind profiler radars (see Resolution 217 (WRC-97)).', 116);
INSERT INTO spectrum_australian_footnotes(footnote_ref, footnote_text, page) VALUES('AUS90', 'In consideration of Resolution 217 (WRC-97), the use by wind profiler radars is confined to the sub-bands 448–450 MHz and 1 270– 1 295 MHz.', 116);
INSERT INTO spectrum_australian_footnotes(footnote_ref, footnote_text, page) VALUES('AUS91', 'Use of the mobile service is limited to Australian, State and Territory Government purposes. The Department of Defence is normally consulted in considering non-defence use of this service.', 116);
INSERT INTO spectrum_australian_footnotes(footnote_ref, footnote_text, page) VALUES('AUS92', 'The band 202.9–203.1 MHz may be used by stations of the space operation service (space-to-Earth) on condition that harmful interference is not caused to stations of the services allocated in this band.', 116);
INSERT INTO spectrum_australian_footnotes(footnote_ref, footnote_text, page) VALUES('AUS93', 'The band may be used by stations of the aeronautical mobile (OR) service for the purposes of defence on condition that harmful interference will not be caused to stations of the space research (deep space)(space-to-Earth) service in this band.', 117);
INSERT INTO spectrum_australian_footnotes(footnote_ref, footnote_text, page) VALUES('AUS94', 'The following bands are intended to be used principally for the purposes of defence: 420.8–421.2 MHz, 424.8–425.2 MHz, 427.8–428.2 MHz. The Department of Defence is normally consulted in considering non- defence use of these bands.', 117);
INSERT INTO spectrum_australian_footnotes(footnote_ref, footnote_text, page) VALUES('AUS95', 'This band may be used by stations of the fixed and mobile services for the purposes of defence on condition that harmful interference is not caused to stations of other services allocated in this band.', 117);
INSERT INTO spectrum_australian_footnotes(footnote_ref, footnote_text, page) VALUES('AUS96', 'This band may be used by stations of the fixed service on condition that harmful interference is not caused to stations of other services operating in accordance with this Spectrum Plan or the Radio Regulations.', 117);
INSERT INTO spectrum_australian_footnotes(footnote_ref, footnote_text, page) VALUES('AUS98', 'The harmonised frequency ranges in the 400 MHz band are used for national security, law enforcement, and first and second responder agencies. These agencies include police, fire, ambulance, and emergency rescue. These agencies are normally consulted about use of this spectrum for government purposes via the Commonwealth, State and Territory representative arrangements established by the National Coordinating Committee for Government Radiocommunications2. The harmonised band comprises the following frequency ranges: 403–403.98125 MHz, 405.01875–406 MHz, 408.64375–410.54375 MHz, 412.46875–413.43125 MHz, 414.46875–415.44375 MHz, 418.09375–430 MHz, 457.50625–459.9875 MHz, 467.50625–469.9875 MHz. 2 The National Coordinating Committee for Government Radiocommunications (NCCGR) is a standing representative committee of the National Emergency Management Committee and was established by agreement of First Ministers in 2004 and replaced the Inter-Government Spectrum Harmonisation Committee (ISHC). It was formed to support a national will to address the core issues of spectrum and inter-jurisdictional operations and to ensure that the relevant issues are considered and discussed within a national framework. The NCCGR consists of representatives from Australian jurisdictions and Australian Government Departments and has been formed with the endorsement of jurisdiction Premiers/Chief Ministers (see Preamble, Constitution of the NCCGR March 2012). Part 3', 117);
INSERT INTO spectrum_australian_footnotes(footnote_ref, footnote_text, page) VALUES('AUS99', 'The band 420.8–421.2 MHz is also allocated to the amateur service on a secondary basis.', 118);
INSERT INTO spectrum_australian_footnotes(footnote_ref, footnote_text, page) VALUES('AUS100', 'This band is designated for use by the Australian Defence Force and Department of Defence. The Department of Defence is to be consulted in considering non-defence use of this band.', 118);
INSERT INTO spectrum_australian_footnotes(footnote_ref, footnote_text, page) VALUES('AUS100A', 'This service is designated for use by the Australian Defence Force and Department of Defence. The Department of Defence is to be consulted in considering non-defence use of this service.', 118);
INSERT INTO spectrum_australian_footnotes(footnote_ref, footnote_text, page) VALUES('AUS101', 'This band is designated to be used principally for the purposes of defence and national security. The Department of Defence is normally consulted in considering non-defence use of this band.', 118);
INSERT INTO spectrum_australian_footnotes(footnote_ref, footnote_text, page) VALUES('AUS101A', 'This service is designated to be used principally for the purposes of defence and national security. The Department of Defence is normally consulted in considering non-defence use of this service.', 118);
INSERT INTO spectrum_australian_footnotes(footnote_ref, footnote_text, page) VALUES('AUS102', 'This band is intended to be used principally for the purposes of defence of Australia, law enforcement and emergency services.', 118);
INSERT INTO spectrum_australian_footnotes(footnote_ref, footnote_text, page) VALUES('AUS102A', 'This service is intended to be used principally for the purposes of defence of Australia, law enforcement and emergency services.', 118);
INSERT INTO spectrum_australian_footnotes(footnote_ref, footnote_text, page) VALUES('AUS103', 'The Murchison Radioastronomy Observatory (MRO) (latitude 26° 42'' 10.4" S, longitude 116° 39'' 37.0" E) hosts the Australian Square Kilometre Array Pathfinder (ASKAP) operating in the band 700– 1 800 MHz and the Murchison Widefield Array (MWA) operating in the band 80–300 MHz.', 118);
INSERT INTO spectrum_australian_footnotes(footnote_ref, footnote_text, page) VALUES('AUS104', 'Under subsection 31(1) of the Act parts of the radiofrequency spectrum, including the band 520–694 MHz, are designated as being primarily for broadcasting purposes and referred for planning in accordance with Part 3 of the Broadcasting Services Act 1992.', 118);
INSERT INTO spectrum_australian_footnotes(footnote_ref, footnote_text, page) VALUES('AUS105', 'This band may be used by stations of the radiolocation service for meteorological and aeronautical surveillance radar, on condition that potential harmful interference is accepted from services operating in adjacent bands in accordance with a spectrum licence.', 118);
INSERT INTO spectrum_australian_footnotes(footnote_ref, footnote_text, page) VALUES('AUS106', 'The band 2103.406-2109.406 MHz may be used by the space operation (space-to-Earth), space research (space-to-Earth) and Earth exploration-satellite (space-to-Earth) services to support the operation of the Bilateration Ranging Transponder System earth station facility near Alice Springs (latitude 23° 45'' 25.3" S, longitude 133° 52'' 58.2" E)', 118);
INSERT INTO spectrum_australian_footnotes(footnote_ref, footnote_text, page) VALUES('AUS106A', 'The band 2284.5–2290.5 MHz may be used by the space operation (Earth-to-space), space research (Earth-to-space) and Earth exploration-satellite (Earth-to-space) services to support the operation of the Bilateration Ranging Transponder System earth station facility near Alice Springs (latitude 23° 45'' 25.3" S, longitude 133° 52'' 58.2" E)', 119);
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text, page) VALUES('53', 'Administrations authorising the use of frequencies below 8.3 kHz shall ensure that no harmful interference is caused to services to which the bands above 8.3 kHz are allocated.', 120);
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text, page) VALUES('54', 'Administrations conducting scientific research using frequencies below 8.3 kHz are urged to advise other administrations that may be concerned in order that such research may be afforded all practicable protection from harmful interference.', 120);
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text, page) VALUES('54A', 'Use of the 8.3–11.3 kHz frequency band by stations in the meteorological aids service is limited to passive use only. In the band 9–11.3 kHz, meteorological aids stations shall not claim protection from stations of the radionavigation service submitted for notification to the Bureau prior to 1 January 2013. For sharing between stations of the meteorological aids service and stations in the radionavigation service submitted for notification after this date, the most recent version of Recommendation ITU-R RS.1881 should be applied.', 120);
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text, page) VALUES('54B', 'Additional allocation: in Algeria, Saudi Arabia, Bahrain, Egypt, the United Arab Emirates, the Russian Federation, Iran (Islamic Republic of), Iraq, Kuwait, Lebanon, Morocco, Qatar, the Syrian Arab Republic, Sudan and Tunisia, the frequency band 8.3–', 120);
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text, page) VALUES('9', 'kHz is also allocated to the radionavigation, fixed and mobile services on a primary basis. ( ) WRC-15', 120);
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text, page) VALUES('54C', 'Additional allocation: in China, the frequency band 8.3–9 kHz is also allocated to the maritime radionavigation and maritime mobile services on a primary basis.', 120);
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text, page) VALUES('55', 'Additional allocation: in Armenia, the Russian Federation, Georgia, Kyrgyzstan, Tajikistan, and Turkmenistan, the frequency band 14–17 kHz is also allocated to the radionavigation service on a primary basis. ( ) WRC-15', 120);
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text, page) VALUES('56', 'The stations of services to which the bands 14–19.95 kHz and 20.05–70 kHz and in Region 1 also the bands 72–84 kHz and 86–90 kHz are allocated may transmit standard frequency and time signals. Such stations shall be afforded protection from harmful interference. In Armenia, Azerbaijan, Belarus, the Russian Federation, Georgia, Kazakhstan, Kyrgyzstan, Tajikistan and Turkmenistan, the frequencies 25 kHz and', 120);
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text, page) VALUES('50', 'kHz will be used for this purpose under the same conditions. ( ) WRC-12', 120);
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text, page) VALUES('57', 'The use of the bands 14–19.95 kHz, 20.05–70 kHz and 70–90 kHz (72–84 kHz and 86–', 120);
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text, page) VALUES('90', 'kHz in Region 1) by the maritime mobile service is limited to coast radiotelegraph stations (A1A and F1B only). Exceptionally, the use of class J2B or J7B emissions is authorised subject to the necessary bandwidth not exceeding that normally used for class A1A or F1B emissions in the band concerned.', 120);
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text, page) VALUES('58', 'Additional allocation: in Armenia, Azerbaijan, Georgia, Kazakhstan, Kyrgyzstan, the Russian Federation, Tajikistan and Turkmenistan, the band 67–70 kHz is also allocated to the radionavigation service on a primary basis. ( ) WRC-2000', 121);
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text, page) VALUES('59', 'Different category of service: in Bangladesh and Pakistan, the allocation of the bands 70–72 kHz and 84–86 kHz to the fixed and maritime mobile services is on a primary basis (see No. 33). ( ) WRC-2000', 121);
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text, page) VALUES('60', 'In the bands 70–90 kHz (70–86 kHz in Region 1) and 110–130 kHz (112–130 kHz in Region 1), pulsed radionavigation systems may be used on condition that they do not cause harmful interference to other services to which these bands are allocated.', 121);
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text, page) VALUES('61', 'In Region 2, the establishment and operation of stations in the maritime radionavigation service in the bands 70–90 kHz and 110–130 kHz shall be subject to agreement obtained under No. 9.21 with administrations whose services, operating in accordance with the Table, may be affected. However, stations of the fixed, maritime mobile and radiolocation services shall not cause harmful interference to stations in the maritime radionavigation service established under such agreements.', 121);
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text, page) VALUES('62', 'Administrations which operate stations in the radionavigation service in the band 90–', 121);
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text, page) VALUES('110', 'kHz are urged to coordinate technical and operating characteristics in such a way as to avoid harmful interference to the services provided by these stations.', 121);
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text, page) VALUES('64', 'Only classes A1A or F1B, A2C, A3C, F1C or F3C emissions are authorised for stations of the fixed service in the bands allocated to this service between 90 kHz and 160 kHz (148.5 kHz in Region 1) and for stations of the maritime mobile service in the bands allocated to this service between 110 kHz and 160 kHz (148.5 kHz in Region 1). Exceptionally, class J2B or J7B emissions are also authorised in the bands between', 121);
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text, page) VALUES('110', 'kHz and 160 kHz (148.5 kHz in Region 1) for stations of the maritime mobile service.', 121);
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text, page) VALUES('65', 'Different category of service: in Bangladesh, the allocation of the bands 112– 117.6 kHz and 126–129 kHz to the fixed and maritime mobile services is on a primary basis (see No. 33). (WRC-2000)', 121);
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text, page) VALUES('66', 'Different category of service: in Germany, the allocation of the band 115–117.6 kHz to the fixed and maritime mobile services is on a primary basis (see No. 33) and to the radionavigation service on a secondary basis (see No. 32).', 121);
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text, page) VALUES('67', 'Additional allocation: in Kyrgyzstan, and Turkmenistan, the frequency band 130– 148.5 kHz is also allocated to the radionavigation service on a secondary basis. Within and between these countries this service shall have an equal right to operate. (WRC-19)', 121);
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text, page) VALUES('67A', 'Stations in the amateur service using frequencies in the band 135.7–137.8 kHz shall not exceed a maximum radiated power of 1 W (e.i.r.p) and shall not cause harmful interference to stations of the radionavigation service operating in countries listed in No. 67. (WRC-07) International Footnotes Part 4', 121);
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text, page) VALUES('67B', 'The use of the frequency band 135.7–137.8 kHz in Algeria, Egypt, Iraq, Lebanon, Syrian Arab Republic, Sudan, South Sudan and Tunisia is limited to the fixed and maritime mobile services. The amateur service shall not be used in the above-mentioned countries in the frequency band 135.7–137.8 kHz, and this should be taken into account by the countries authorising such use. (WRC-19)', 122);
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text, page) VALUES('68', 'Alternative allocation: in Congo (Rep. of the), the Dem. Rep. of the Congo and South Africa, the frequency band 160–200 kHz is allocated to the fixed service on a primary basis. (WRC-15)', 122);
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text, page) VALUES('69', 'Additional allocation: in Somalia, the band 200–255 kHz is also allocated to the aeronautical radionavigation service on a primary basis.', 122);
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text, page) VALUES('70', 'Alternative allocation: in Angola, Botswana, Burundi, the Central African Rep., Congo (Rep. of the), Eswatini, Ethiopia, Kenya, Lesotho, Madagascar, Malawi, Mozambique, Namibia, Nigeria, Oman, the Dem. Rep. of the Congo, South Africa, Tanzania, Chad, Zambia and Zimbabwe, the frequency band 200–283.5 kHz is allocated to the aeronautical radionavigation service on a primary basis. (WRC-19)', 122);
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text, page) VALUES('73', 'The band 285–325 kHz (283.5–325 kHz in Region 1), in the maritime radionavigation service may be used to transmit supplementary navigational information using narrow- band techniques, on condition that no harmful interference is caused to radiobeacon stations operating in the radionavigation service. (WRC-97)', 122);
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text, page) VALUES('74', 'Additional Allocation: in Region 1, the frequency band 285.3–285.7 kHz is also allocated to the maritime radionavigation service (other than radiobeacons) on a primary basis.', 122);
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text, page) VALUES('75', 'Different category of service: in Armenia, Azerbaijan, Belarus, Georgia, Moldova, Kyrgyzstan, the Russian Federation, Tajikistan, Turkmenistan, Ukraine and the Black Sea areas of Romania, the allocation of the band 315–325 kHz to the maritime radionavigation service is on a primary basis under the condition that in the Baltic Sea area, the assignment of frequencies in this band to new stations in the maritime or aeronautical radionavigation services shall be subject to prior consultation between the administrations concerned. (WRC-07)', 122);
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text, page) VALUES('76', 'The frequency 410 kHz is designated for radio direction-finding in the maritime radionavigation service. The other radionavigation services to which the band 405–', 122);
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text, page) VALUES('415', 'kHz is allocated shall not cause harmful interference to radio direction-finding in the band 406.5–413.5 kHz.', 122);
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text, page) VALUES('77', 'Different category of service: in Australia, China, the French overseas communities of Region 3, Korea (Rep. of), India, Iran (Islamic Republic of), Japan, Pakistan, Papua New Guinea, the Dem. People’s Rep. of Korea and Sri Lanka, the allocation of the frequency band 415–495 kHz to the aeronautical radionavigation service is on a primary basis. In Armenia, Azerbaijan, Belarus, the Russian Federation, Kazakhstan, Latvia, Uzbekistan and Kyrgyzstan, the allocation of the frequency band 435–495 kHz to the aeronautical radionavigation service is on a primary basis. Administrations in all the aforementioned countries shall take all practical steps necessary to ensure that aeronautical radionavigation stations in the frequency band 435–495 kHz do not cause interference to reception by coast stations of transmissions from ship stations on frequencies designated for ship stations on a worldwide basis. ( ) WRC-19', 122);
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text, page) VALUES('78', 'Different category of service: in Cuba, the United States and Mexico the allocation of the band 415–435 kHz to the aeronautical radionavigation service is on a primary basis.', 123);
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text, page) VALUES('79', 'In the maritime mobile service, the frequency bands 415–495 kHz and 505–526.5 kHz are limited to radiotelegraphy and may also be used for the NAVDAT system in accordance with the most recent version of Recommendation ITU-R M.2010, subject to agreement between interested and affected administrations. NAVDAT transmitting stations are limited to coast stations. ( ) WRC-19', 123);
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text, page) VALUES('79A', 'When establishing coast stations in the NAVTEX service on the frequencies 490 kHz,', 123);
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text, page) VALUES('518', 'kHz and 4 209.5 kHz, administrations are strongly recommended to coordinate the operating characteristics in accordance with the procedures of the International Maritime Organisation (IMO) (see Resolution 339 (Rev.WRC-07)). ( ) WRC-07', 123);
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text, page) VALUES('80', 'In Region 2, the use of the band 435–495 kHz by the aeronautical radionavigation service is limited to non-directional beacons not employing voice transmission.', 123);
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text, page) VALUES('80A', 'The maximum equivalent isotropically radiated power (e.i.r.p.) of stations in the amateur service using frequencies in the band 472–479 kHz shall not exceed 1 W. Administrations may increase this limit of e.i.r.p. to 5 W in portions of their territory which are at a distance of over 800 km from the borders of Algeria, Saudi Arabia, Azerbaijan, Bahrain, Belarus, China, Comoros, Djibouti, Egypt, United Arab Emirates, the Russian Federation, Iran (Islamic Republic of), Iraq, Jordan, Kazakhstan, Kuwait, Lebanon, Libya, Morocco, Mauritania, Oman, Uzbekistan, Qatar, Syrian Arab Republic, Kyrgyzstan, Somalia, Sudan, Tunisia, Ukraine and Yemen. In this frequency band, stations on the amateur service shall not cause harmful interference to, or claim protection from, stations of the aeronautical radionavigation service.', 123);
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text, page) VALUES('80B', 'The use of the frequency band 472–479 kHz in Algeria, Saudi Arabia, Azerbaijan, Bahrain, Belarus, China, Comoros, Djibouti, Egypt, United Arab Emirates, the Russian Federation, Iraq, Jordan, Kazakhstan, Kuwait, Lebanon, Libya, Mauritania, Oman, Uzbekistan, Qatar, Syrian Arab Republic, Kyrgyzstan, Somalia, Sudan, Tunisia, and Yemen is limited to the maritime mobile and aeronautical radionavigation services. The amateur service shall not be used in the above-mentioned countries in this frequency band, and this should be taken into account by the countries authorising such use.', 123);
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text, page) VALUES('82', 'In the maritime mobile service, the frequency 490 kHz is to be used exclusively for the transmission by coast stations of navigational and meteorological warnings and urgent information to ships, by means of narrow-band direct-printing telegraphy. The conditions for use of the frequency 490 kHz are prescribed in Articles 31 and 52. In using the band 415–495 kHz for the aeronautical radionavigation service, administrations are requested to ensure that no harmful interference is caused to the International Footnotes Part 4 frequency 490 kHz. In using the frequency band 472–479 kHz for the amateur service, administrations shall ensure that no harmful interference is caused to the frequency', 123);
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text, page) VALUES('490', 'kHz. ( ) WRC-12', 124);
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text, page) VALUES('82C', 'The frequency band 495–505 kHz is used for the international NAVDAT system as described in the most recent version of Recommendation ITU-R M.2010. NAVDAT transmitting stations are limited to coast stations. ( ) WRC-19', 124);
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text, page) VALUES('84', 'The conditions for the use of the frequency 518 kHz by the maritime mobile service are prescribed in Articles 31 and 52 ( ) WRC-07', 124);
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text, page) VALUES('86', 'In Region 2, in the band 525–535 kHz the carrier power of broadcasting stations shall not exceed 1 kW during the day and 250 W at night.', 124);
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text, page) VALUES('87', 'Additional allocation: in Angola, Botswana, Eswatini, Lesotho, Malawi, Mozambique, Namibia and Niger, the frequency band 526.5–535 kHz is also allocated to the mobile service on a secondary basis. ( ) WRC-19', 124);
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text, page) VALUES('87A', 'Additional allocation: in Uzbekistan, the band 526.5–1 606.5 kHz is also allocated to the radionavigation service on a primary basis. Such use is subject to agreement obtained under No. 9.21 with administrations concerned and limited to ground-based radiobeacons in operation on 27 October 1997 until the end of their lifetime. ( ) WRC-97', 124);
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text, page) VALUES('88', 'Additional allocation: in China, the band 526.5–535 kHz is also allocated to the aeronautical radionavigation service on a secondary basis.', 124);
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text, page) VALUES('89', 'In Region 2, the use of the band 1 605–1 705 kHz by stations of the broadcasting service is subject to the Plan established by the Regional Administrative Radio Conference (Rio de Janeiro, 1988). The examination of frequency assignments to stations of the fixed and mobile services in the band 1 625–1 705 kHz shall take account of the allotments appearing in the Plan established by the Regional Administrative Radio Conference (Rio de Janeiro, 1988).', 124);
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text, page) VALUES('90', 'In the band 1 605–1 705 kHz, in cases where a broadcasting station of Region 2 is concerned, the service area of the maritime mobile stations in Region 1 shall be limited to that provided by ground-wave propagation.', 124);
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text, page) VALUES('91', 'Additional allocation: in the Philippines and Sri Lanka, the band 1 606.5–1 705 kHz is also allocated to the broadcasting service on a secondary basis. ( ) WRC-97', 124);
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text, page) VALUES('92', 'Some countries of Region 1 use radiodetermination systems in the bands 1 606.5–', 124);
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text, page) VALUES('1', '625 kHz, 1 635–1 800 kHz, 1 850–2 160 kHz, 2 194–2 300 kHz, 2 502–2 850 kHz and 3 500–3 800 kHz, subject to agreement obtained under No. 9.21. The radiated mean power of these stations shall not exceed 50 W.', 124);
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text, page) VALUES('93', 'Additional allocation: in Armenia, Azerbaijan, Belarus, the Russian Federation, Georgia, Hungary, Kazakhstan, Latvia, Lithuania, Mongolia, Nigeria, Uzbekistan, Poland, Kyrgyzstan, Slovakia, Tajikistan, Chad, Turkmenistan and Ukraine, the frequency bands 1 625–1 635 kHz, 1 800–1 810 kHz and 2 160–2 170 kHz are also allocated to the fixed and land mobile services on a primary basis, subject to agreement obtained under No. 9.21. ( ) WRC-15', 124);
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text, page) VALUES('96', 'In Germany, Armenia, Austria, Azerbaijan, Belarus, Croatia, Denmark, Estonia, the Russian Federation, Finland, Georgia, Hungary, Ireland, Iceland, Israel, Kazakhstan, Latvia, Liechtenstein, Lithuania, Malta, Moldova, Norway, Uzbekistan, Poland, Kyrgyzstan, Slovakia, the Czech Rep., the United Kingdom, Sweden, Switzerland, Tajikistan, Turkmenistan and Ukraine, administrations may allocate up to 200 kHz to their amateur service in the frequency bands 1 715–1 800 kHz and 1 850–2 000 kHz. However, when allocating the frequency bands within this range to their amateur service, administrations shall, after prior consultation with administrations of neighbouring countries, take such steps as may be necessary to prevent harmful interference from their amateur service to the fixed and mobile services of other countries. The mean power of any amateur station shall not exceed 10 W. ( ) WRC-15', 125);
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text, page) VALUES('97', 'In Region 3, the Loran system operates either on 1 850 kHz or 1 950 kHz, the bands occupied being 1 825–1 875 kHz and 1 925–1 975 kHz respectively. Other services to which the band 1 800–2 000 kHz is allocated may use any frequency therein on condition that no harmful interference is caused to the Loran system operating on', 125);
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text, page) VALUES('1', '850 kHz or 1 950 kHz.', 125);
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text, page) VALUES('98', 'Alternative allocation: in Armenia, Azerbaijan, Belarus, Belgium, Cameroon, Congo (Rep. of the), Denmark, Egypt, Eritrea, Spain, Ethiopia, the Russian Federation, Georgia, Greece, Italy, Kazakhstan, Lebanon, Lithuania, the Syrian Arab Republic, Kyrgyzstan, Somalia, Tajikistan, Tunisia, Turkmenistan and Turkey, the frequency band 1 810–1 830 kHz is allocated to the fixed and mobile, except aeronautical mobile, services on a primary basis. ( ) WRC-15', 125);
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text, page) VALUES('99', 'Additional allocation: in Saudi Arabia, Austria, Iraq, Libya, Uzbekistan, Slovakia, Romania, Slovenia, Chad, and Togo, the band 1 810–1 830 kHz is also allocated to the fixed and mobile, except aeronautical mobile, services on a primary basis. ( ) WRC-12', 125);
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text, page) VALUES('100', 'In Region 1, the authorisation to use the band 1 810–1 830 kHz by the amateur service in countries situated totally or partially north of 40° N shall be given only after consultation with the countries mentioned in Nos. 98 and 99 to define the necessary steps to be taken to prevent harmful interference between amateur stations and stations of other services operating in accordance with Nos. 98 and 99.', 125);
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text, page) VALUES('102', 'Alternative allocation: in Bolivia, Chile, Paraguay and Peru, the frequency band', 125);
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text, page) VALUES('1', '850–2 000 kHz is allocated to the fixed, mobile except aeronautical mobile, radiolocation and radionavigation services on a primary basis. ( ) WRC-15', 125);
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text, page) VALUES('103', 'In Region 1, in making assignments to stations in the fixed and mobile services in the bands 1 850–2 045 kHz, 2 194–2 498 kHz, 2 502–2 625 kHz and 2 650–2 850 kHz, administrations should bear in mind the special requirements of the maritime mobile service. International Footnotes Part 4', 125);
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text, page) VALUES('104', 'In Region 1, the use of the band 2 025–2 045 kHz by the meteorological aids service is limited to oceanographic buoy stations.', 126);
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text, page) VALUES('105', 'In Region 2, except in Greenland, coast stations and ship stations using radiotelephony in the band 2 065–2 107 kHz shall be limited to class J3E emissions and to a peak envelope power not exceeding 1 kW. Preferably, the following carrier frequencies should be used: 2 065.0 kHz, 2 079.0 kHz, 2 082.5 kHz, 2 086.0 kHz, 2 093.0 kHz,', 126);
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text, page) VALUES('2', '096.5 kHz, 2 100.0 kHz and 2 103.5 kHz. In Argentina and Uruguay, the carrier frequencies 2 068.5 kHz and 2 075.5 kHz are also used for this purpose, while the frequencies within the band 2 072–2 075.5 kHz are used as provided in No. 52.165.', 126);
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text, page) VALUES('106', 'In Regions 2 and 3, provided no harmful interference is caused to the maritime mobile service, the frequencies between 2 065 kHz and 2 107 kHz may be used by stations of the fixed service communicating only within national borders and whose mean power does not exceed 50 W. In notifying the frequencies, the attention of the Bureau should be drawn to these provisions.', 126);
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text, page) VALUES('107', 'Additional allocation: in Saudi Arabia, Eritrea, Eswatini, Ethiopia, Iraq, Libya and Somalia, the frequency band 2 160–2 170 kHz is also allocated to the fixed and mobile, except aeronautical mobile (R), services on a primary basis. The mean power of stations in these services shall not exceed 50 W. ( ) WRC-19', 126);
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text, page) VALUES('108', 'The carrier frequency 2 182 kHz is an international distress and calling frequency for radiotelephony. The conditions for the use of the band 2 173.5–2 190.5 kHz are prescribed in Articles 31 and 52. ( ) WRC-07', 126);
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text, page) VALUES('109', 'The frequencies 2 187.5 kHz, 4 207.5 kHz, 6 312 kHz, 8 414.5 kHz, 12 577 kHz and', 126);
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text, page) VALUES('16', '804.5 kHz are international distress frequencies for digital selective calling. The conditions for the use of these frequencies are prescribed in Article 31.', 126);
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text, page) VALUES('110', 'The frequencies 2 174.5 kHz, 4 177.5 kHz, 6 268 kHz, 8 376.5 kHz, 12 520 kHz and', 126);
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text, page) VALUES('16', '695 kHz are international distress frequencies for narrow-band direct-printing telegraphy. The conditions for the use of these frequencies are prescribed in Article 31.', 126);
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text, page) VALUES('111', 'The carrier frequencies 2 182 kHz, 3 023 kHz, 5 680 kHz, 8 364 kHz and the frequencies 121.5 MHz, 156.525 MHz, 156.8 MHz and 243 MHz may also be used, in accordance with the procedures in force for terrestrial radiocommunication services, for search and rescue operations concerning manned space vehicles. The conditions for the use of the frequencies are prescribed in Article 31. The same applies to the frequencies 10 003 kHz, 14 993 kHz and 19 993 kHz, but in each of these cases emissions must be confined in a band of ±3 kHz about the frequency. ( ) WRC-07', 126);
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text, page) VALUES('112', 'Alternative allocation: in Sri Lanka, the frequency band 2 194–2 300 kHz is allocated to the fixed and mobile, except aeronautical mobile, services on a primary basis. ( ) WRC-19', 126);
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text, page) VALUES('113', 'For the conditions for the use of the bands 2 300–2 495 kHz (2 498 kHz in Region 1),', 127);
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text, page) VALUES('3', '200–3 400 kHz, 4 750–4 995 kHz and 5 005–5 060 kHz by the broadcasting service, see Nos. 16 to 20, 21 and 23.3 to 23.10.', 127);
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text, page) VALUES('114', 'Alternative allocation: in Iraq, the frequency band 2 502–2 625 kHz is allocated to the fixed and mobile, except aeronautical mobile, services on a primary basis. ( ) WRC-19', 127);
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text, page) VALUES('115', 'The carrier (reference) frequencies 3 023 kHz and 5 680 kHz may also be used, in accordance with Article 31, by stations of the maritime mobile service engaged in coordinated search and rescue operations. ( ) WRC-07', 127);
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text, page) VALUES('116', 'Administrations are urged to authorise the use of the band 3 155–3 195 kHz to provide a common worldwide channel for low power wireless hearing aids. Additional channels for these devices may be assigned by administrations in the bands between 3 155 kHz and 3 400 kHz to suit local needs. It should be noted that frequencies in the range 3 000 kHz to 4 000 kHz are suitable for hearing aid devices which are designed to operate over short distances within the induction field.', 127);
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text, page) VALUES('117', 'Alternative allocation: in Côte d’Ivoire, Egypt, Liberia, Sri Lanka and Togo, the frequency band 3 155–3 200 kHz is allocated to the fixed and mobile, except aeronautical mobile, services on a primary basis. ( ) WRC-19', 127);
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text, page) VALUES('118', 'Additional allocation: in the United States, Mexico and Peru, the frequency band', 127);
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text, page) VALUES('3', '230–3 400 kHz is also allocated to the radiolocation service on a secondary basis. ( ) WRC-19', 127);
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text, page) VALUES('119', 'Additional allocation: in Peru, the frequency band 3 500–3 750 kHz is also allocated to the fixed and mobile services on a primary basis. ( ) WRC-15', 127);
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text, page) VALUES('122', 'Alternative allocation: in Bolivia, Chile, Ecuador, Paraguay and Peru, the frequency band 3 750–4 000 kHz is allocated to the fixed and mobile, except aeronautical mobile, services on a primary basis. ( ) WRC-15', 127);
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text, page) VALUES('123', 'Additional allocation: in Botswana, Eswatini, Lesotho, Malawi, Mozambique, Namibia, South Africa, Zambia and Zimbabwe, the frequency band 3 900–3 950 kHz is also allocated to the broadcasting service on a primary basis, subject to agreement obtained under No. 9.21. ( ) WRC-19', 127);
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text, page) VALUES('125', 'Additional allocation: in Greenland, the band 3 950–4 000 kHz is also allocated to the broadcasting service on a primary basis. The power of the broadcasting stations operating in this band shall not exceed that necessary for a national service and shall in no case exceed 5 kW.', 127);
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text, page) VALUES('126', 'In Region 3, the stations of those services to which the band 3 995–4 005 kHz is allocated may transmit standard frequency and time signals. International Footnotes Part 4', 127);
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text, page) VALUES('127', 'The use of the band 4 000–4 063 kHz by the maritime mobile service is limited to ship stations using radiotelephony (see No. 52.220 and Appendix 17).', 128);
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text, page) VALUES('128', 'Frequencies in the frequency bands 4 063–4 123 kHz and 4 130–4 438 kHz may be used exceptionally by stations in the fixed service, communicating only within the boundary of the country in which they are located, with a mean power not exceeding', 128);
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text, page) VALUES('50', 'W, on condition that harmful interference is not caused to the maritime mobile service. In addition, in Afghanistan, Argentina, Armenia, Belarus, Botswana, Burkina Faso, the Central African Rep., China, the Russian Federation, Georgia, India, Kazakhstan, Mali, Niger, Pakistan, Kyrgyzstan, Tajikistan, Chad, Turkmenistan and Ukraine, in the frequency bands 4 063–4 123 kHz, 4 130–4 133 kHz and 4 408–', 128);
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text, page) VALUES('4', '438 kHz, stations in the fixed service, with a mean power not exceeding 1 kW, can be operated on condition that they are situated at least 600 km from the coast and that harmful interference is not caused to the maritime mobile service. ( ) WRC-19', 128);
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text, page) VALUES('130', 'The conditions for the use of the carrier frequencies 4 125 kHz and 6 215 kHz are prescribed in Articles 31 and 52. ( ) WRC-07', 128);
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text, page) VALUES('131', 'The frequency 4 209.5 kHz is used exclusively for the transmission by coast stations of meteorological and navigational warnings and urgent information to ships by means of narrow-band direct-printing techniques. (WRC-97)', 128);
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text, page) VALUES('132', 'The frequencies 4 210 kHz, 6 314 kHz, 8 416.5 kHz, 12 579 kHz, 16 806.5 kHz,', 128);
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text, page) VALUES('19', '680.5 kHz, 22 376 kHz and 26 100.5 kHz are the international frequencies for the transmission of Maritime Safety Information (MSI) (see Appendix 17).', 128);
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text, page) VALUES('132A', 'Stations in the radiolocation service shall not cause harmful interference to, or claim protection from, stations operating in the fixed or mobile services. Applications of the radiolocation service are limited to oceanographic radars operating in accordance with Resolution 612 (Rev.WRC-12).', 128);
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text, page) VALUES('132B', 'Alternative allocation: in Armenia, Belarus, Moldova and Kyrgyzstan, the frequency band 4 438–4 488 kHz is allocated to the fixed and mobile, except aeronautical mobile (R), services on a primary basis. ( ) WRC-19', 128);
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text, page) VALUES('133', 'Different category of service: in Armenia, Azerbaijan, Belarus, the Russian Federation, Georgia, Kazakhstan, Latvia, Lithuania, Niger, Uzbekistan, Kyrgyzstan, Tajikistan, Turkmenistan and Ukraine, the allocation of the band 5 130–5 250 kHz to the mobile, except aeronautical mobile, service is on a primary basis (see No. 33). ( ) WRC-12', 128);
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text, page) VALUES('133A', 'Alternative allocation: in Armenia, Belarus, Moldova and Kyrgyzstan, the frequency bands 5 250–5 275 kHz and 26 200–26 350 kHz are allocated to the fixed and mobile, except aeronautical mobile, services on a primary basis. ( ) WRC-19', 128);
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text, page) VALUES('133B', 'Stations in the amateur service using the frequency band 5 351.5–5 366.5 kHz shall not exceed a maximum radiated power of 15 W (e.i.r.p.). However, in Region 2 in Mexico, stations in the amateur service using the frequency band 5 351.5–5 366.5 kHz shall not exceed a maximum radiated power of 20 W (e.i.r.p.). In the following Region 2 countries: Antigua and Barbuda, Argentina, Bahamas, Barbados, Belize, Bolivia, Brazil, Chile, Colombia, Costa Rica, Cuba, Dominican Republic, Dominica, El Salvador, Ecuador, Grenada, Guatemala, Guyana, Haiti, Honduras, Jamaica, Nicaragua, Panama, Paraguay, Peru, Saint Lucia, Saint Kitts and Nevis, Saint Vincent and the Grenadines, Suriname, Trinidad and Tobago, Uruguay, Venezuela, as well as the overseas countries and territories within the Kingdom of the Netherlands in Region 2, stations in the amateur service using the frequency band 5 351.5–', 128);
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text, page) VALUES('5', '366.5 kHz shall not exceed a maximum radiated power of 25 W (e.i.r.p.). ( ) WRC-19', 129);
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text, page) VALUES('134', 'The use of the frequency bands 5 900–5 950 kHz, 7 300–7 350 kHz, 9 400–9 500 kHz,', 129);
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text, page) VALUES('11', '600–11 650 kHz, 12 050–12 100 kHz, 13 570–13 600 kHz, 13 800–13 870 kHz,', 129);
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text, page) VALUES('15', '600–15 800 kHz, 17 480–17 550 kHz and 18 900–19 020 kHz by the broadcasting service is subject to the application of the procedure of Article 12. Administrations are encouraged to use these frequency bands to facilitate the introduction of digitally modulated emissions in accordance with the provisions of Resolution 517 (Rev.WRC- 19). ( ) WRC-19', 129);
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text, page) VALUES('136', 'Additional allocation: frequencies in the band 5 900–5 950 kHz may be used by stations in the following services, communicating only within the boundary of the country in which they are located: fixed service (in all three Regions), land mobile service (in Region 1), mobile except aeronautical mobile (R) service (in Regions 2 and 3), on the condition that harmful interference is not caused to the broadcasting service. When using frequencies for these services, administrations are urged to use the minimum power required and to take account of the seasonal use of frequencies by the broadcasting service published in accordance with the Radio Regulations. ( ) WRC-07', 129);
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text, page) VALUES('137', 'On condition that harmful interference is not caused to the maritime mobile service, the bands 6 200–6 213.5 kHz and 6 220.5–6 525 kHz may be used exceptionally by stations in the fixed service, communicating only within the boundary of the country in which they are located, with a mean power not exceeding 50 W. At the time of notification of these frequencies, the attention of the Bureau will be drawn to the above conditions.', 129);
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text, page) VALUES('138', 'The following bands:', 129);
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text, page) VALUES('6', '765–6 795 kHz (centre frequency 6 780 kHz), 433.05–434.79 MHz (centre frequency 433.92 MHz) in Region 1 except in the countries mentioned in No. 280, 61–61.5 GHz (centre frequency 61.25 GHz), 122–123 GHz (centre frequency 122.5 GHz), and 244–246 GHz (centre frequency 245 GHz) are designated for industrial, scientific and medical (ISM) applications. The use of these frequency bands for ISM applications shall be subject to special authorisation by the administration concerned, in agreement with other administrations whose radiocommunication services might be affected. In applying this provision, administrations shall have due regard to the latest relevant ITU-R Recommendations.', 129);
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text, page) VALUES('138A', 'Until 29 March 2009, the band 6 765–7 000 kHz is allocated to the fixed service on a primary basis and to the land mobile service on a secondary basis. After this date, this International Footnotes Part 4 band is allocated to the fixed and the mobile except aeronautical mobile (R) services on a primary basis. ( ) WRC-03', 129);
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text, page) VALUES('139', 'Different category of service: until 29 March 2009, in Armenia, Azerbaijan, Belarus, the Russian Federation, Georgia, Kazakhstan, Latvia, Lithuania, Mongolia, Uzbekistan, Kyrgyzstan, Tajikistan, Turkmenistan and Ukraine, the allocation of the band 6 765–', 130);
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text, page) VALUES('7', '000 kHz to the land mobile service is on a primary basis (see No. 33). ( ) WRC-07', 130);
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text, page) VALUES('140', 'Additional allocation: in Angola, Iraq, Somalia and Togo, the frequency band 7 000–', 130);
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text, page) VALUES('7', '050 kHz is also allocated to the fixed service on a primary basis. ( ) WRC-15', 130);
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text, page) VALUES('141', 'Alternative allocation: in Egypt, Eritrea, Ethiopia, Guinea, Libya, Madagascar and Niger, the band 7 000–7 050 kHz is allocated to the fixed service on a primary basis. ( ) WRC-12', 130);
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text, page) VALUES('141A', 'Additional allocation: in Uzbekistan and Kyrgyzstan, the bands 7 000–7 100 kHz and', 130);
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text, page) VALUES('7', '100–7 200 kHz are also allocated to the fixed and land mobile services on a secondary basis. ( ) WRC-03', 130);
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text, page) VALUES('141B', 'Additional allocation: in Algeria, Saudi Arabia, Australia, Bahrain, Botswana, Brunei Darussalam, China, Comoros, Korea (Rep. of), Diego Garcia, Djibouti, Egypt, United Arab Emirates, Eritrea, Guinea, Indonesia, Iran (Islamic Republic of), Japan, Jordan, Kuwait, Libya, Mali, Morocco, Mauritania, Niger, New Zealand, Oman, Papua New Guinea, Qatar, the Syrian Arab Republic, the Dem. People’s Rep. of Korea, Singapore, Sudan, South Sudan, Tunisia, Viet Nam and Yemen, the frequency band 7 100–', 130);
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text, page) VALUES('7', '200 kHz is also allocated to the fixed and the mobile, except aeronautical mobile (R), services on a primary basis. ( ) WRC-19', 130);
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text, page) VALUES('141C', 'In Regions 1 and 3, the band 7 100–7 200 kHz is allocated to the broadcasting service until 29 March 2009 on a primary basis. ( ) WRC-03', 130);
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text, page) VALUES('142', 'Until 29 March 2009, the use of the band 7 100–7 300 kHz in Region 2 by the amateur service shall not impose constraints on the broadcasting service intended for use within Region 1 and Region 3. After 29 March 2009 the use of the band 7 200–7 300 kHz in Region 2 by the amateur service shall not impose constraints on the broadcasting service intended for use within Region 1 and Region 3. ( ) WRC-03', 130);
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text, page) VALUES('143', 'Additional allocation: frequencies in the band 7 300–7 350 kHz may be used by stations in the fixed service and in the land mobile service, communicating only within the boundary of the country in which they are located, on condition that harmful interference is not caused to the broadcasting service. When using frequencies for these services, administrations are urged to use the minimum power required and to take account of the seasonal use of frequencies by the broadcasting service published in accordance with the Radio Regulations. (WRC-07)', 130);
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text, page) VALUES('143A', 'In Region 3, the band 7 350–7 450 kHz is allocated, until 29 March 2009, to the fixed service on a primary basis and to the land mobile service on a secondary basis. After', 130);
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text, page) VALUES('29', 'March 2009, frequencies in this band may be used by stations in the above- mentioned services, communicating only within the boundary of the country in which they are located, on condition that harmful interference is not caused to the broadcasting service. When using frequencies for these services, administrations are urged to use the minimum power required and to take account of the seasonal use of frequencies by the broadcasting service published in accordance with the Radio Regulations. ( ) WRC-03', 130);
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text, page) VALUES('143B', 'In Region 1, the band 7 350–7 450 kHz is allocated, until 29 March 2009, to the fixed service on a primary basis and to the land mobile service on a secondary basis. After', 131);
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text, page) VALUES('29', 'March 2009, on condition that harmful interference is not caused to the broadcasting service, frequencies in the band 7 350–7 450 kHz may be used by stations in the fixed and land mobile services communicating only within the boundary of the country in which they are located, each station using a total radiated power that shall not exceed', 131);
