INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text, page) VALUES('7', '450 kHz are also allocated to the fixed service on a primary basis. ( ) WRC-12', 131);
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text, page) VALUES('143D', 'In Region 2, the band 7 350–7 400 kHz is allocated, until 29 March 2009, to the fixed service on a primary basis and to the land mobile service on a secondary basis. After', 131);
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text, page) VALUES('29', 'March 2009, frequencies in this band may be used by stations in the above- mentioned services, communicating only within the boundary of the country in which they are located, on condition that harmful interference is not caused to the broadcasting service. When using frequencies for these services, administrations are urged to use the minimum power required and to take account of the seasonal use of frequencies by the broadcasting service published in accordance with the Radio Regulations. ( ) WRC-03', 131);
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text, page) VALUES('143E', 'Until 29 March 2009, the band 7 450–8 100 kHz is allocated to the fixed service on a primary basis and to the land mobile service on a secondary basis. ( ) WRC-03', 131);
