INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text, page) VALUES('16', '420 kHz are prescribed in Articles 31 and 52. ( ) WRC-07', 131);
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text, page) VALUES('145A', 'Stations in the radiolocation service shall not cause harmful interference to, or claim protection from, stations operating in the fixed service. Applications of the radiolocation service are limited to oceanographic radars operating in accordance with Resolution 612 (Rev.WRC-12).', 131);
