INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text, page) VALUES('3', '345.8–3 352.5 MHz, are allocated, administrations are urged to take all practicable steps to protect the radio astronomy service from harmful interference. Emissions from spaceborne or airborne stations can be particularly serious sources of interference to the radio astronomy service (see Nos. 4.5 and 4.6 and Article 29). ( ) WRC-07', 132);
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text, page) VALUES('149A', 'Alternative allocation: in Armenia, Belarus, Moldova and Kyrgyzstan, the frequency band 13 450–13 550 kHz is allocated to the fixed service on a primary basis and to the mobile, except aeronautical mobile (R), service on a secondary basis. ( ) WRC-19', 132);
