INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text, page) VALUES('5', '725–5 875 MHz (centre frequency 5 800 MHz), and 24–24.25 GHz (centre frequency 24.125 GHz) are also designated for industrial, scientific and medical (ISM) applications. Radiocommunication services operating within these bands must accept harmful interference which may be caused by these applications. ISM equipment operating in these bands is subject to the provisions of No. 15.13.', 133);
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text, page) VALUES('151', 'Additional allocation: frequencies in the bands 13 570–13 600 kHz and 13 800–', 133);
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text, page) VALUES('13', '870 kHz may be used by stations in the fixed service and in the mobile except aeronautical mobile (R) service, communicating only within the boundary of the country in which they are located, on the condition that harmful interference is not caused to the broadcasting service. When using frequencies in these services, administrations are urged to use the minimum power required and to take account of the seasonal use of frequencies by the broadcasting service published in accordance with the Radio Regulations. (WRC-07)', 133);
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text, page) VALUES('152', 'Additional allocation: in Armenia, Azerbaijan, China, Côte d’Ivoire, the Russian Federation, Georgia, Iran (Islamic Republic of), Kazakhstan, Uzbekistan, Kyrgyzstan, Tajikistan, Turkmenistan and Ukraine, the band 14 250–14 350 kHz is also allocated to the fixed service on a primary basis. Stations of the fixed service shall not use a radiated power exceeding 24 dBW. ( ) WRC-03', 133);
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text, page) VALUES('153', 'In Region 3, the stations of those services to which the band 15 995–16 005 kHz is allocated may transmit standard frequency and time signals.', 133);
