INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text, page) VALUES('18', '168 kHz is also allocated to the fixed service on a primary basis for use within their boundaries, with a peak envelope power not exceeding 1 kW. ( ) WRC-03', 133);
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text, page) VALUES('155', 'Additional allocation: in Armenia, Azerbaijan, Belarus, the Russian Federation, Georgia, Kazakhstan, Moldova, Mongolia, Uzbekistan, Kyrgyzstan, Slovakia, Tajikistan, Turkmenistan and Ukraine, the band 21 850–21 870 kHz is also allocated to the aeronautical mobile (R) service on a primary basis. ( ) WRC-07', 133);
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text, page) VALUES('155A', 'In Armenia, Azerbaijan, Belarus, Georgia, Kazakhstan, Moldova, Mongolia, Uzbekistan, Kyrgyzstan, Slovakia, the Russian Federation, Tajikistan, Turkmenistan and Ukraine, the use of the band 21 850–21 870 kHz by the fixed service is limited to provision of services related to aircraft flight safety. ( ) WRC-07', 133);
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text, page) VALUES('155B', 'The band 21 870–21 924 kHz is used by the fixed service for provision of services related to aircraft flight safety.', 133);
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text, page) VALUES('156', 'Additional allocation: in Nigeria, the band 22 720–23 200 kHz is also allocated to the meteorological aids service (radiosondes) on a primary basis. International Footnotes Part 4', 133);
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text, page) VALUES('156A', 'The use of the band 23 200–23 350 kHz by the fixed service is limited to provision of services related to aircraft flight safety.', 134);
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text, page) VALUES('157', 'The use of the band 23 350–24 000 kHz by the maritime mobile service is limited to inter-ship radiotelegraphy.', 134);
